```c
// gfortran                 // flang                    // NAG                      // Intel         
void *base_addr;            void *base_addr;            void *base_addr;            void * base_addr;
size_t elem_len;            size_t elem_len;            size_t elem_len;            size_t elem_len;
int version;                int version;                int version;                int version;
